(() => {
 function wireConfirmations() {
 document.addEventListener("submit", (event) => {
 const form = event.target;
 if (!(form instanceof HTMLFormElement)) {
 return;
 }

 const message = form.dataset.confirm;
 if (message && !window.confirm(message)) {
 event.preventDefault();
 }
 });
 }
 function showNotificationToast(notification) {
 let container = document.querySelector("[data-notification-toasts]");
 if (!container) {
 container = document.createElement("div");
 container.dataset.notificationToasts = "";
 container.className = "toast-container position-fixed top-0 end-0 p-3";
 container.style.zIndex = "1080";
 document.body.appendChild(container);
 }
 const toast = document.createElement("div");
 toast.className = "toast align-items-center text-bg-primary border-0";
 toast.role = "status";
 toast.ariaLive = "polite";
 toast.ariaAtomic = "true";
 toast.innerHTML = `
 <div class="d-flex">
 <div class="toast-body">${escapeHtml(notification.message ?? "Нове сповіщення")}</div>
 <button type="button" class="btn-close btn-close-white me-2 m-auto" data-bs-dismiss="toast" aria-label="Закрити"></button>
 </div>`;
 container.appendChild(toast);
 const bootstrapToast = new bootstrap.Toast(toast, { delay: 6000 });
 toast.addEventListener("hidden.bs.toast", () => toast.remove(), { once: true });
 bootstrapToast.show();
 }
 function escapeHtml(value) {
 const element = document.createElement("div");
 element.textContent = value;
 return element.innerHTML;
 }
 function wireRealtimeNotifications() {
 if (!window.signalR) {
 return;
 }
 const connection = new signalR.HubConnectionBuilder()
 .withUrl("/notificationsHub")
 .withAutomaticReconnect()
 .build();
 connection.on("ReceiveNotification", showNotificationToast);
 connection.start().catch((error) => console.error("SignalR notification connection failed.", error));
 }
 document.addEventListener("DOMContentLoaded", () => {
 wireConfirmations();
 wireRealtimeNotifications();
 }, { once: true });
})();

(() => {
 function initAutocomplete(container) {
 const input = container.querySelector("[data-location-input]");
 const suggestions = container.querySelector("[data-location-suggestions]");
 const endpoint = container.dataset.autocompleteUrl;

 if (!input || !suggestions || !endpoint) {
 return;
 }

 let controller = null;
 let activeRequestId = 0;

 function hideSuggestions() {
 suggestions.innerHTML = "";
 suggestions.classList.remove("is-visible");
 }

 function selectSuggestion(value) {
 input.value = value;
 hideSuggestions();
 input.focus();
 }

 async function fetchSuggestions() {
 const query = input.value.trim();
 if (query.length < 2) {
 hideSuggestions();
 return;
 }

 activeRequestId += 1;
 const requestId = activeRequestId;

 if (controller) {
 controller.abort();
 }

 controller = new AbortController();

 try {
 const response = await fetch(`${endpoint}${encodeURIComponent(query)}`, {
 signal: controller.signal
 });

 if (!response.ok) {
 throw new Error("Network error");
 }

 const items = await response.json();
 if (requestId !== activeRequestId || !Array.isArray(items) || items.length === 0) {
 hideSuggestions();
 return;
 }

 suggestions.innerHTML = "";

 for (const item of items) {
 const option = document.createElement("button");
 option.type = "button";
 option.className = "list-group-item list-group-item-action";
 option.textContent = item;
 option.addEventListener("click", () => selectSuggestion(item));
 suggestions.appendChild(option);
 }

 suggestions.classList.add("is-visible");
 } catch (error) {
 if (error.name !== "AbortError") {
 hideSuggestions();
 }
 }
 }

 input.addEventListener("input", fetchSuggestions);
 input.addEventListener("blur", () => {
 window.setTimeout(hideSuggestions, 150);
 });

 document.addEventListener("click", (event) => {
 if (!container.contains(event.target)) {
 hideSuggestions();
 }
 });
 }

 document.addEventListener("DOMContentLoaded", () => {
 document.querySelectorAll("[data-location-autocomplete]").forEach(initAutocomplete);
 }, { once: true });
})();

(() => {
 function toggleEdit(thread, messageId) {
 const viewMode = thread.querySelector(`[data-message-view="${messageId}"]`);
 const editForm = thread.querySelector(`[data-message-edit="${messageId}"]`);

 if (!viewMode || !editForm) {
 return;
 }

 const willShowEditor = editForm.hidden;
 viewMode.hidden = willShowEditor;
 editForm.hidden = !willShowEditor;

 if (willShowEditor) {
 const textarea = editForm.querySelector("textarea");
 if (textarea) {
 textarea.focus();
 textarea.setSelectionRange(textarea.value.length, textarea.value.length);
 }
 }
 }

 function initThread(thread) {
 const scrollContainer = thread.querySelector("[data-chat-messages]");
 if (scrollContainer) {
 scrollContainer.scrollTop = scrollContainer.scrollHeight;
 }

 thread.addEventListener("click", (event) => {
 const toggle = event.target.closest("[data-chat-edit-toggle]");
 if (!toggle) {
 return;
 }

 event.preventDefault();
 toggleEdit(thread, toggle.dataset.chatEditToggle);
 });
 }

 document.addEventListener("DOMContentLoaded", () => {
 document.querySelectorAll("[data-chat-thread]").forEach(initThread);
 }, { once: true });
})();